function WeddingCakes() {
  const cakes = [
    {
      name: "Sweet Moments Bakery",
      experience: "5 Years",
      service: "Wedding Cake Design",
      package:
        "Customized wedding cake, luxury decoration, multiple flavors, and personalized cake styling.",
      contact: "sweetmoments@email.com",
      price: "$500 package",
      image: "https://cdn-icons-png.flaticon.com/512/3075/3075977.png",
    },

    {
      name: "Golden Cake Studio",
      experience: "7 Years",
      service: "Luxury Wedding Cakes",
      package:
        "Premium wedding cakes, floral decoration, custom flavors, and elegant presentation design.",
      contact: "goldencake@email.com",
      price: "$850 package",
      image: "https://cdn-icons-png.flaticon.com/512/2718/2718224.png",
    },

    {
      name: "Dream Cake House",
      experience: "4 Years",
      service: "Modern Wedding Cakes",
      package:
        "Modern cake styling, customized colors, dessert table setup, and special wedding themes.",
      contact: "dreamcake@email.com",
      price: "$450 package",
      image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
    },
  ];

  function requestCake(name) {
    alert("Your request has been sent to " + name);
  }

  return (
    <section className="page-section">
      <div className="page-header">
        <h1>Wedding Cakes</h1>

        <p>
          Find professional wedding cake designers for customized cakes,
          dessert tables, and luxury wedding presentations.
        </p>
      </div>

      <section className="cards">
        {cakes.map((cake, index) => (
          <div className="card" key={index}>
            <img
              src={cake.image}
              alt={cake.name}
              className="service-image"
            />

            <h3>{cake.name}</h3>

            <p><strong>Service:</strong> {cake.service}</p>
            <p><strong>Package Includes:</strong> {cake.package}</p>
            <p><strong>Experience:</strong> {cake.experience}</p>
            <p><strong>Email:</strong> {cake.contact}</p>
            <p><strong>Price:</strong> {cake.price}</p>

            <button
              className="request-btn"
              onClick={() => requestCake(cake.name)}
            >
              Request Service
            </button>
          </div>
        ))}
      </section>
    </section>
  );
}

export default WeddingCakes;
